// Extract basic envelope info from DocuSign webhook
const body = $json.body;
const event = body.event;

console.log('Event received:', event);

// Process both recipient-completed and envelope-completed events
if (event !== 'envelope-completed' && event !== 'recipient-completed') {
  console.log('Skipping - not a completion event');
  return [];
}

const data = body.data || body;

return [{
  json: {
    envelopeId: data.envelopeId,
    accountId: data.accountId,
    recipientId: data.recipientId || null,
    event: event
  }
}];

// Parse the full envelope data from DocuSign
const envelope = $json;

// Only proceed if envelope is fully completed
if (envelope.status !== 'completed') {
  console.log('Envelope not fully completed yet, status:', envelope.status);
  return [];
}

// Extract all form fields from all recipients
const allFormFields = {};

if (envelope.recipients && envelope.recipients.signers) {
  envelope.recipients.signers.forEach(signer => {
    if (signer.tabs && signer.tabs.textTabs) {
      signer.tabs.textTabs.forEach(tab => {
        allFormFields[tab.tabLabel] = tab.value || '';
      });
    }
  });
}

return [{
  json: {
    envelopeId: envelope.envelopeId,
    status: envelope.status,
    emailSubject: envelope.emailSubject,
    completedDateTime: envelope.completedDateTime,
    accountId: envelope.accountId,
    formFields: allFormFields,
    accountIdForDownload: envelope.accountId,
    envelopeIdForDownload: envelope.envelopeId
  }
}];

const base64Data = $json.data;
const filename = "signed_document.pdf";

// Create downloadable data URL
const downloadUrl = `data:application/pdf;base64,${base64Data}`;

return [{
  json: {
    pdfDownloadUrl: downloadUrl,
    pdfFilename: filename
  }
}];

